const UNITS = { ms: 1, s: 1000, m: 60000, h: 3600000, d: 86400000 };
// Sticky regex; ms before m so the longer token wins.
const TOKEN_RE = /(\d+)(ms|s|m|h|d)/y;

function parseDuration(str) {
  if (typeof str !== 'string' || str.length === 0) {
    throw new Error(`parseDuration: invalid input: ${str}`);
  }

  if (/^\d+$/.test(str)) {
    return parseInt(str, 10);
  }

  let total = 0;
  let pos = 0;
  TOKEN_RE.lastIndex = 0;

  while (pos < str.length) {
    TOKEN_RE.lastIndex = pos;
    const match = TOKEN_RE.exec(str);
    if (!match) {
      throw new Error(`parseDuration: unexpected token at position ${pos} in "${str}"`);
    }
    total += parseInt(match[1], 10) * UNITS[match[2]];
    pos += match[0].length;
  }

  return total;
}

